const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

export const SettingsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<Theme>('dark');
  const [language, setLanguage] = useState<Language>('fa');
  const [accentColor, setAccentColor] = useState<AccentColor>('blue');

  useEffect(() => {
    // Apply Theme
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  useEffect(() => {
    // Apply Language Direction
    const root = window.document.documentElement;
    root.setAttribute('lang', language);
    root.setAttribute('dir', language === 'fa' ? 'rtl' : 'ltr');
  }, [language]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  const toggleLanguage = () => {
    setLanguage(prev => prev === 'fa' ? 'en' : 'fa');
  };

  const t = (key: string): string => {
    return translations[key]?.[language] || key;
  };

  const getThemeColors = () => {
    switch(accentColor) {
        case 'emerald': return { primary: '#059669', hover: '#047857', light: '#ecfdf5', text: '#065f46' };
        case 'violet': return { primary: '#7c3aed', hover: '#6d28d9', light: '#f5f3ff', text: '#5b21b6' };
        case 'amber': return { primary: '#d97706', hover: '#b45309', light: '#fffbeb', text: '#92400e' };
        case 'rose': return { primary: '#e11d48', hover: '#be123c', light: '#fff1f2', text: '#9f1239' };
        default: return { primary: '#2563eb', hover: '#1d4ed8', light: '#eff6ff', text: '#1e40af' }; // blue
    }
  };

  return (
    <SettingsContext.Provider value={{ 
      theme, 
      language, 
      accentColor,
      toggleTheme, 
      toggleLanguage, 
      setAccentColor,
      t,
      dir: language === 'fa' ? 'rtl' : 'ltr',
      themeColors: getThemeColors()
    }}>
      {children}
    </SettingsContext.Provider>
  );
};

export const useSettings = () => {
  const context = useContext(SettingsContext);
  if (!context) {
    throw new Error('useSettings must be used within a SettingsProvider');
  }
  return context;
};

import { GoogleGenAI, Chat } from "@google/genai";
import { Exhaust } from "../types";
import { STANDARDS } from "../constants";

// Initialize carefully - if offline, we still define 'ai' but API calls will be guarded
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Chat session management
let chatSession: Chat | null = null;

export const resetChatSession = () => {
  chatSession = null;
};

export const sendChatMessage = async (message: string): Promise<string> => {
  if (!navigator.onLine) {
    return "اتصال اینترنت برقرار نیست. لطفاً برای دریافت پاسخ هوشمند، اتصال خود را بررسی کنید.";
  }

  try {
    if (!chatSession) {
      chatSession = ai.chats.create({
        model: 'gemini-3-pro-preview',
        config: {
          systemInstruction: 'You are an intelligent assistant for an industrial environmental monitoring system called EcoMonitor. You help engineers interpret emission data (CO, NOx, SO2, PM, O2), understand ISO 14001 standards, and troubleshoot boiler efficiency issues. Your responses should be technical, concise, and helpful. Use Persian (Farsi) language. Always format your response in a way that is easy to read in a chat window.',
        },
      });
    }

    const response = await chatSession.sendMessage({ message });
    return response.text || "متاسفانه پاسخی دریافت نشد.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "خطا در ارتباط با سرور هوشمند. لطفاً مجدداً تلاش کنید.";
  }
};

export const generateExhaustAnalysis = async (exhaustData: Exhaust): Promise<string> => {
  if (!navigator.onLine) {
    return "برای تحلیل هوشمند داده‌ها نیاز به اینترنت است. لطفاً اتصال خود را بررسی کرده و مجدداً تلاش کنید.";
  }

  const dataDescription = Object.entries(exhaustData.data).map(([pollutant, value]) => {
    const std = STANDARDS[pollutant];
    return `- ${std.name} (${pollutant}): ${value} ${std.unit} (Standard Limit: ${std.limit})`;
  }).join('\n');

  const prompt = `
    You are an expert environmental engineer and boiler system specialist. 
    Analyze the following emission data for an industrial boiler:

    Exhaust Name: ${exhaustData.name}
    Location: ${exhaustData.location}
    Last Check Date: ${exhaustData.lastCheck}

    Pollutant Data:
    ${dataDescription}

    Please provide a detailed technical report in Persian (Farsi) covering:
    1. **Overall Status**: A summary of the boiler's compliance with environmental standards.
    2. **Problem Identification**: Identify specific pollutants that exceed or approach limits and explain the potential mechanical or chemical causes (e.g., lean fuel mixture, low combustion temperature, sulfur content).
    3. **Actionable Recommendations**: Provide specific engineering solutions to fix the issues.
    4. **Priority**: Rank the actions from Critical to Low priority.
    5. **Estimation**: Rough time and resource estimation for the fixes.

    Format the response using clean Markdown with headers and bullet points. Use professional technical Persian terminology.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "خطا در دریافت پاسخ از هوش مصنوعی. لطفاً مجدداً تلاش کنید.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "خطا در برقراری ارتباط با سرور تحلیل هوشمند. لطفاً اتصال اینترنت خود را بررسی کنید.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Activity, FileText, TrendingUp, Menu, Zap, BarChart3, Info, Moon, Sun, Languages, Palette, MessageSquare, Wifi, WifiOff } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { DataEntry } from './components/DataEntry';
import { AnalysisResult } from './components/AnalysisResult';
import { MeasurementHistory } from './components/HistoryLog';
import { ExhaustDetails } from './components/ExhaustDetails';
import { ChatBot } from './components/ChatBot';
import { Exhaust, PollutantData, AIAnalysisResult, TabType } from './types';
import { INITIAL_EXHAUSTS } from './constants';
import { generateExhaustAnalysis } from './services/geminiService';
import { useSettings, AccentColor } from './contexts/SettingsContext';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType | 'chat'>('dashboard');

  // Initialize state from LocalStorage or fallback to constants
  const [exhausts, setExhausts] = useState<Exhaust[]>(() => {
    try {
      const saved = localStorage.getItem('ecomonitor_exhausts');
      return saved ? JSON.parse(saved) : INITIAL_EXHAUSTS;
    } catch (e) {
      console.error("Failed to load from local storage", e);
      return INITIAL_EXHAUSTS;
    }
  });

  const [aiAnalysis, setAiAnalysis] = useState<AIAnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // Navigation visibility state for scroll behavior
  const [isNavVisible, setIsNavVisible] = useState(true);
  const lastScrollY = useRef(0);

  const { theme, toggleTheme, language, toggleLanguage, t, dir, accentColor, setAccentColor, themeColors } = useSettings();

  // Persist data when changed
  useEffect(() => {
    localStorage.setItem('ecomonitor_exhausts', JSON.stringify(exhausts));
  }, [exhausts]);

  // Monitor Network Status
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;

      // Always show when at the very top
      if (currentScrollY < 50) {
        setIsNavVisible(true);
        lastScrollY.current = currentScrollY;
        return;
      }

      // Hide when scrolling down, show when scrolling up
      if (currentScrollY > lastScrollY.current) {
        setIsNavVisible(false);
      } else {
        setIsNavVisible(true);
      }
      lastScrollY.current = currentScrollY;
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleAddData = (exhaustId: string, newData: PollutantData, period: string) => {
    setExhausts(prev => prev.map(exhaust => {
      if (exhaust.id === parseInt(exhaustId)) {
        return {
          ...exhaust,
          data: newData,
          lastCheck: new Date().toLocaleDateString(language === 'fa' ? 'fa-IR' : 'en-US'),
          history: [
            ...exhaust.history, 
            {
                period: period,
                date: new Date().toLocaleDateString(language === 'fa' ? 'fa-IR' : 'en-US'),
                data: newData
            }
          ]
        };
      }
      return exhaust;
    }));
    setActiveTab('details');
  };

  const handleAddExhaust = (name: string, location: string) => {
    const newId = exhausts.length > 0 ? Math.max(...exhausts.map(e => e.id)) + 1 : 1;
    const newExhaust: Exhaust = {
      id: newId,
      name,
      location,
      data: { CO: 0, CO2: 0, SO2: 0, NOx: 0, PM: 0, O2: 0 },
      history: [],
      lastCheck: 'ثبت نشده'
    };
    setExhausts(prev => [...prev, newExhaust]);
  };

  const handleImportData = (data: Exhaust[]) => {
      setExhausts(data);
  };

  const handleAnalyze = async (exhaust: Exhaust, switchTab: boolean = true) => {
    if (!isOnline) {
      alert(t('error.offlineDesc'));
      return;
    }

    setIsAnalyzing(true);
    try {
      const resultText = await generateExhaustAnalysis(exhaust);
      setAiAnalysis({
        exhaustId: exhaust.id,
        analysis: resultText,
        timestamp: new Date().toLocaleString(language === 'fa' ? 'fa-IR' : 'en-US')
      });
      if (switchTab) setActiveTab('analysis');
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: t('nav.dashboard'), icon: Activity },
    { id: 'details', label: t('nav.details'), icon: Info },
    { id: 'data-entry', label: t('nav.dataEntry'), icon: FileText },
    { id: 'analysis', label: t('nav.analysis'), icon: TrendingUp },
    { id: 'chat', label: t('nav.chat'), icon: MessageSquare },
    { id: 'history', label: t('nav.history'), icon: BarChart3 }
  ];

  const colors: { id: AccentColor; bg: string }[] = [
    { id: 'blue', bg: 'bg-blue-600' },
    { id: 'emerald', bg: 'bg-emerald-600' },
    { id: 'violet', bg: 'bg-violet-600' },
    { id: 'amber', bg: 'bg-amber-600' },
    { id: 'rose', bg: 'bg-rose-600' },
  ];

  return (
    <div 
      className="min-h-screen bg-gray-50 dark:bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] dark:from-slate-900 dark:via-slate-900 dark:to-black text-slate-900 dark:text-white transition-colors duration-300" 
      dir={dir}
      style={{
        '--theme-primary': themeColors.primary,
        '--theme-hover': themeColors.hover,
        '--theme-light': themeColors.light,
        '--theme-text': themeColors.text,
      } as React.CSSProperties}
    >
      <div className="max-w-7xl mx-auto p-4 md:p-6 lg:p-8">

        {/* Header */}
        <header className="mb-10 animate-in slide-in-from-top-5 duration-700">
          <div className="bg-white dark:bg-slate-800 rounded-3xl p-8 shadow-xl dark:shadow-slate-900/20 border border-gray-200 dark:border-slate-700 relative overflow-hidden transition-all duration-300">
             {/* Gradient Background based on Theme */}
             <div 
               className="absolute top-0 right-0 w-full h-full opacity-0 dark:opacity-20 pointer-events-none transition-colors duration-500"
               style={{ background: `linear-gradient(to right, ${themeColors.primary}, transparent)` }}
             />

            <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl md:text-4xl font-black mb-2 tracking-tight">
                  {t('app.title')} <span className="text-transparent bg-clip-text" style={{ backgroundImage: `linear-gradient(to right, ${themeColors.primary}, ${themeColors.hover})` }}>EcoMonitor</span>
                </h1>
                <p className="text-slate-600 dark:text-slate-400 font-medium text-lg max-w-2xl">
                  {t('app.subtitle')}
                </p>
              </div>

              <div className="flex flex-col sm:flex-row items-center gap-4">

                {/* Online Status Indicator */}
                <div 
                  className={`flex items-center gap-2 px-3 py-2 rounded-xl border text-sm font-bold transition-all ${
                    isOnline 
                      ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800 text-emerald-600 dark:text-emerald-400' 
                      : 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-600 dark:text-red-400'
                  }`}
                  title={isOnline ? t('status.online') : t('status.offline')}
                >
                  {isOnline ? <Wifi size={18} /> : <WifiOff size={18} />}
                  <span className="hidden sm:inline">{isOnline ? t('status.online') : t('status.offline')}</span>
                </div>

                {/* Color Picker */}
                <div className="flex items-center gap-2 p-2 bg-gray-100 dark:bg-slate-900/50 rounded-xl border border-gray-200 dark:border-slate-700">
                    <Palette size={16} className="text-slate-500 ml-1" />
                    {colors.map(c => (
                        <button
                            key={c.id}
                            onClick={() => setAccentColor(c.id)}
                            className={`w-6 h-6 rounded-full transition-transform hover:scale-110 ${c.bg} ${accentColor === c.id ? 'ring-2 ring-offset-2 ring-slate-400 dark:ring-white scale-110' : 'opacity-70 hover:opacity-100'}`}
                        />
                    ))}
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={toggleTheme}
                        className="p-3 rounded-xl bg-gray-100 dark:bg-white/10 text-slate-700 dark:text-white border border-gray-200 dark:border-white/10 hover:bg-gray-200 dark:hover:bg-white/20 transition-all"
                    >
                        {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                    </button>
                    <button 
                        onClick={toggleLanguage}
                        className="p-3 rounded-xl bg-gray-100 dark:bg-white/10 text-slate-700 dark:text-white border border-gray-200 dark:border-white/10 hover:bg-gray-200 dark:hover:bg-white/20 transition-all font-bold w-12"
                    >
                        {language === 'fa' ? 'En' : 'فا'}
                    </button>
                </div>

                <div className="hidden md:flex items-center gap-3 bg-blue-50 dark:bg-white/10 backdrop-blur-md px-4 py-2.5 rounded-xl border border-blue-100 dark:border-white/10">
                    <Zap className="text-amber-500 dark:text-yellow-400 fill-amber-500 dark:fill-yellow-400" />
                    <span className="font-bold text-slate-800 dark:text-white">{t('gemini.powered')}</span>
                </div>
              </div>
            </div>
          </div>
        </header>

        {/* Navigation - Modified to auto-collapse on scroll and be horizontal on mobile */}
        <nav 
          className={`flex flex-row gap-3 mb-8 bg-white/60 dark:bg-slate-900/50 p-2 rounded-2xl border border-gray-200 dark:border-slate-800 backdrop-blur-sm sticky top-4 z-50 shadow-lg dark:shadow-xl overflow-x-auto transition-all duration-300 ${
            isNavVisible 
              ? 'translate-y-0 opacity-100' 
              : '-translate-y-[200%] opacity-0 pointer-events-none'
          }`}
        >
          {navItems.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 min-w-[140px] py-4 px-6 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-3 text-sm md:text-base whitespace-nowrap ${
                activeTab === tab.id 
                  ? 'text-white shadow-lg scale-[1.02]' 
                  : 'bg-transparent text-slate-500 dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-slate-200'
              }`}
              style={activeTab === tab.id ? { backgroundColor: themeColors.primary, boxShadow: `0 10px 15px -3px ${themeColors.primary}50` } : {}}
            >
              <tab.icon size={22} strokeWidth={2.5} />
              {tab.label}
            </button>
          ))}
        </nav>

        {/* Main Content Area */}
        <main className="min-h-[500px]">
          {activeTab === 'dashboard' && (
            <Dashboard 
              exhausts={exhausts} 
              onAnalyze={(e) => handleAnalyze(e, true)} 
              isAnalyzing={isAnalyzing} 
              isOnline={isOnline}
            />
          )}

          {activeTab === 'details' && (
            <ExhaustDetails 
              exhausts={exhausts}
              aiAnalysis={aiAnalysis}
              isAnalyzing={isAnalyzing}
              onAnalyze={handleAnalyze}
              isOnline={isOnline}
            />
          )}

          {activeTab === 'data-entry' && (
            <DataEntry 
              exhausts={exhausts} 
              onAddData={handleAddData} 
              onAddExhaust={handleAddExhaust}
              onImportData={handleImportData}
            />
          )}

          {activeTab === 'analysis' && (
            <AnalysisResult 
              analysis={aiAnalysis}
              exhausts={exhausts} 
              onBack={() => setActiveTab('dashboard')}
            />
          )}

          {activeTab === 'chat' && (
             <ChatBot isOnline={isOnline} />
          )}

          {activeTab === 'history' && (
            <MeasurementHistory exhausts={exhausts} />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { 
  BarChart, Bar, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar 
} from 'recharts';
import { AlertCircle, Activity, WifiOff } from 'lucide-react';
import { Exhaust } from '../types';
import { STANDARDS, DIAGNOSTIC_SYSTEM } from '../constants';
import { useSettings } from '../contexts/SettingsContext';

interface DashboardProps {
  exhausts: Exhaust[];
  onAnalyze: (exhaust: Exhaust) => void;
  isAnalyzing: boolean;
  isOnline: boolean;
}

export const Dashboard: React.FC<DashboardProps> = ({ exhausts, onAnalyze, isAnalyzing, isOnline }) => {
  const { themeColors, t } = useSettings();

  const calculateStatus = (value: number, limit: number) => {
    const percentage = (value / limit) * 100;
    if (percentage <= 80) return { status: 'خوب', color: '#10b981', level: 'safe' };
    if (percentage <= 100) return { status: 'قابل قبول', color: '#f59e0b', level: 'warning' };
    if (percentage <= 120) return { status: 'خطر', color: '#ef4444', level: 'danger' };
    return { status: 'بحرانی', color: '#dc2626', level: 'critical' };
  };

  const getExhaustOverallStatus = (exhaustData: any) => {
    let maxPercentage = 0;
    Object.keys(STANDARDS).forEach(pollutant => {
      const percentage = (exhaustData[pollutant] / STANDARDS[pollutant].limit) * 100;
      if (percentage > maxPercentage) maxPercentage = percentage;
    });
    return calculateStatus(maxPercentage * STANDARDS.CO.limit / 100, STANDARDS.CO.limit);
  };

  const getDetailedDiagnostic = (exhaustData: Exhaust) => {
    const diagnostics: any[] = [];
    Object.entries(exhaustData.data).forEach(([pollutant, value]) => {
      const limit = STANDARDS[pollutant].limit;
      const percentage = ((value as number) / limit) * 100;

      if (percentage > 100) {
        const severity = percentage > 120 ? 'veryHigh' : 'high';
        diagnostics.push({
          pollutant: STANDARDS[pollutant].name,
          value: value,
          limit: limit,
          percentage: percentage.toFixed(1),
          issue: DIAGNOSTIC_SYSTEM[pollutant][severity as 'high' | 'veryHigh']
        });
      }
    });
    return diagnostics;
  };

  const getRadarData = (exhaustData: any) => {
    return Object.keys(STANDARDS).map(pollutant => ({
      pollutant: STANDARDS[pollutant].name,
      value: (exhaustData[pollutant] / STANDARDS[pollutant].limit) * 100,
      fullMark: 100
    }));
  };

  const comparisonData = Object.keys(STANDARDS).map(pollutant => ({
    name: STANDARDS[pollutant].name,
    استاندارد: STANDARDS[pollutant].limit,
    ...exhausts.reduce((acc: any, exhaust) => {
      acc[exhaust.name] = exhaust.data[pollutant];
      return acc;
    }, {})
  }));

  return (
    <div className="w-full space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {exhausts.map(exhaust => {
          const overallStatus = getExhaustOverallStatus(exhaust.data);
          const diagnostics = getDetailedDiagnostic(exhaust);

          return (
            <div key={exhaust.id} className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-2xl p-6 shadow-xl border border-gray-200 dark:border-slate-700/50 hover:border-gray-300 dark:hover:border-slate-600 transition-all min-w-0">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h3 className="text-xl font-bold mb-1 text-slate-800 dark:text-white">{exhaust.name}</h3>
                  <p className="text-sm text-slate-500 dark:text-slate-400">{exhaust.location}</p>
                  <p className="text-xs text-slate-400 dark:text-slate-500 mt-1">آخرین بررسی: {exhaust.lastCheck}</p>
                </div>
                <div className={`px-4 py-2 rounded-full font-bold text-white shadow-lg`} style={{backgroundColor: overallStatus.color}}>
                  {overallStatus.status}
                </div>
              </div>

              <div className="mb-6 h-[220px] w-full" dir="ltr">
                <ResponsiveContainer width="99%" height="100%">
                  <RadarChart cx="50%" cy="50%" outerRadius="70%" data={getRadarData(exhaust.data)}>
                    <PolarGrid stroke="#94a3b8" strokeDasharray="3 3" />
                    <PolarAngleAxis dataKey="pollutant" tick={{fill: '#64748b', fontSize: 12}} />
                    <PolarRadiusAxis angle={90} domain={[0, 150]} tick={{fill: '#64748b'}} />
                    <Radar name="درصد استاندارد" dataKey="value" stroke={themeColors.primary} fill={themeColors.primary} fillOpacity={0.5} />
                  </RadarChart>
                </ResponsiveContainer>
              </div>

              <div className="space-y-3">
                {Object.entries(exhaust.data).map(([pollutant, value]) => {
                  const limit = STANDARDS[pollutant].limit;
                  const val = value as number;
                  const status = calculateStatus(val, limit);
                  const percentage = ((val / limit) * 100).toFixed(1);

                  return (
                    <div key={pollutant} className="bg-gray-50 dark:bg-slate-700/50 rounded-lg p-3 border border-gray-100 dark:border-slate-600/30">
                      <div className="flex justify-between items-center mb-2">
                        <span className="font-semibold text-slate-700 dark:text-slate-200">{STANDARDS[pollutant].name}</span>
                        <span className="text-sm font-medium" style={{color: status.color}}>{status.status}</span>
                      </div>
                      <div className="flex items-center gap-3">
                        <div className="flex-1 bg-gray-200 dark:bg-slate-900 rounded-full h-2.5">
                          <div 
                            className="h-full rounded-full transition-all duration-1000 ease-out"
                            style={{
                              width: `${Math.min(parseFloat(percentage), 100)}%`,
                              backgroundColor: status.color
                            }}
                          />
                        </div>
                        <span className="text-xs font-mono text-slate-500 dark:text-slate-400 min-w-[80px] text-left" dir="ltr">
                          {val} / {limit}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>

              {diagnostics.length > 0 && (
                <div className="mt-4 bg-red-50 dark:bg-red-950/40 border border-red-200 dark:border-red-500/30 rounded-xl p-4">
                  <h4 className="font-bold mb-2 flex items-center gap-2 text-red-600 dark:text-red-400">
                    <AlertCircle size={18} />
                    هشدار سیستم:
                  </h4>
                  {diagnostics.map((diag, idx) => (
                    <div key={idx} className="text-sm mb-2 last:mb-0 text-slate-600 dark:text-slate-300">
                      <strong className="text-red-500 dark:text-red-300">{diag.pollutant}</strong> ({diag.percentage}%):
                      <p className="mt-1 text-xs opacity-80">{diag.issue}</p>
                    </div>
                  ))}
                </div>
              )}

              <button
                onClick={() => onAnalyze(exhaust)}
                disabled={isAnalyzing || !isOnline}
                title={!isOnline ? t('error.offlineDesc') : ''}
                className="group w-full mt-6 py-3.5 rounded-xl font-bold text-white shadow-lg transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                style={isOnline 
                  ? { backgroundImage: `linear-gradient(to right, ${themeColors.primary}, ${themeColors.hover})`, boxShadow: `0 10px 15px -3px ${themeColors.primary}30` } 
                  : { backgroundColor: '#94a3b8' }
                }
              >
                {!isOnline ? (
                  <>
                    <WifiOff size={20} />
                    {t('error.offline')}
                  </>
                ) : isAnalyzing ? (
                  <>
                    <Activity className="animate-spin" size={20} />
                    در حال تحلیل هوشمند...
                  </>
                ) : (
                  <>
                    <Activity size={20} className="group-hover:scale-110 transition-transform" />
                    تحلیل پیشرفته با AI
                  </>
                )}
              </button>
            </div>
          );
        })}
      </div>

      <div className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-2xl p-6 shadow-xl border border-gray-200 dark:border-slate-700/50 w-full min-w-0">
        <h3 className="text-xl font-bold mb-6 text-slate-800 dark:text-white flex items-center gap-2">
          <Activity className="text-green-500" />
          مقایسه جامع آلاینده‌ها با استانداردهای ISO 14001
        </h3>
        <div className="h-[400px] w-full" dir="ltr">
          <ResponsiveContainer width="99%" height="100%">
            <BarChart data={comparisonData} barSize={20}>
              <CartesianGrid strokeDasharray="3 3" stroke="#94a3b8" strokeOpacity={0.2} vertical={false} />
              <XAxis dataKey="name" tick={{fill: '#64748b', fontSize: 12}} axisLine={false} tickLine={false} dy={10} />
              <YAxis tick={{fill: '#64748b', fontSize: 12}} axisLine={false} tickLine={false} />
              <Tooltip 
                cursor={{fill: 'rgba(255,255,255,0.05)'}}
                contentStyle={{backgroundColor: '#1e293b', border: '1px solid #475569', borderRadius: '12px', color: '#f8fafc', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.5)'}}
                labelStyle={{color: '#94a3b8', marginBottom: '0.5rem'}}
              />
              <Legend wrapperStyle={{paddingTop: '20px'}} />
              <Bar dataKey="استاندارد" fill="#94a3b8" radius={[4, 4, 0, 0]} name="حد استاندارد" />
              {exhausts.map((exhaust, idx) => (
                <Bar 
                  key={exhaust.id} 
                  dataKey={exhaust.name} 
                  fill={[themeColors.primary, '#f59e0b', '#8b5cf6', '#ec4899', '#6366f1'][idx % 5]} 
                  radius={[4, 4, 0, 0]} 
                  name={exhaust.name}
                >
                  {comparisonData.map((entry: any, index: number) => {
                    const value = entry[exhaust.name] as number;
                    const limit = entry['استاندارد'] as number;
                    const { color } = calculateStatus(value, limit);
                    return <Cell key={`cell-${index}`} fill={color} />;
                  })}
                </Bar>
              ))}
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

