             <button
                onClick={() => onAnalyze(selectedExhaust, false)}
                disabled={isAnalyzing || !isOnline}
                title={!isOnline ? t('error.offlineDesc') : ''}
                className="w-full sm:w-auto text-white py-3 px-8 rounded-xl font-bold shadow-lg transition-all active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-2"
                style={isOnline 
                  ? { backgroundImage: `linear-gradient(to right, ${themeColors.primary}, ${themeColors.hover})`, boxShadow: `0 10px 15px -3px ${themeColors.primary}30` }
                  : { backgroundColor: '#94a3b8' }
                }
              >
                {!isOnline ? (
                  <>
                    <WifiOff size={20} />
                    {t('error.offline')}
                  </>
                ) : isAnalyzing ? (
                  <>
                    <Activity className="animate-spin" size={20} />
                    {t('loading')}
                  </>
                ) : (
                  <>
                    <Zap size={20} className="fill-white" />
                    {currentAnalysis ? t('details.reAnalyzeBtn') : t('details.getAnalysisBtn')}
                  </>
                )}
              </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, RefreshCw, MessageSquare, Sparkles, WifiOff } from 'lucide-react';
import { useSettings } from '../contexts/SettingsContext';
import { sendChatMessage, resetChatSession } from '../services/geminiService';

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: string;
}

interface ChatBotProps {
  isOnline: boolean;
}

export const ChatBot: React.FC<ChatBotProps> = ({ isOnline }) => {
  const { t, themeColors, dir } = useSettings();
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: t('chat.welcome'),
      timestamp: new Date().toLocaleTimeString()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading || !isOnline) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date().toLocaleTimeString()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await sendChatMessage(userMsg.text);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date().toLocaleTimeString()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleReset = () => {
    resetChatSession();
    setMessages([{
      id: Date.now().toString(),
      role: 'model',
      text: t('chat.welcome'),
      timestamp: new Date().toLocaleTimeString()
    }]);
  };

  return (
    <div className="animate-in slide-in-from-bottom-5 duration-500 h-[calc(100vh-250px)] min-h-[500px] flex flex-col">
      <div className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-t-2xl p-4 shadow-sm border-x border-t border-gray-200 dark:border-slate-700/50 flex justify-between items-center">
        <div className="flex items-center gap-3">
            <div className="p-3 rounded-xl bg-gradient-to-tr from-purple-500 to-indigo-500 text-white shadow-lg shadow-purple-500/20">
                <Sparkles size={24} />
            </div>
            <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-white">{t('nav.chat')}</h2>
                <div className="flex items-center gap-2">
                  <p className="text-xs text-slate-500 dark:text-slate-400">Gemini 3 Pro Preview</p>
                  {!isOnline && (
                    <span className="text-xs bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400 px-2 py-0.5 rounded-full flex items-center gap-1">
                      <WifiOff size={10} />
                      {t('status.offline')}
                    </span>
                  )}
                </div>
            </div>
        </div>
        <button 
            onClick={handleReset}
            className="p-2 text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/10 rounded-lg transition-all tooltip"
            title={t('chat.clear')}
        >
            <RefreshCw size={20} />
        </button>
      </div>

      <div className="flex-1 bg-white/50 dark:bg-slate-900/50 backdrop-blur-sm border-x border-gray-200 dark:border-slate-700/50 overflow-y-auto p-4 space-y-4 custom-scrollbar">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex items-end gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div 
                className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
                    msg.role === 'user' 
                    ? 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300' 
                    : 'bg-gradient-to-tr from-purple-500 to-indigo-500 text-white'
                }`}
            >
                {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
            </div>

            <div className={`max-w-[80%] rounded-2xl p-4 shadow-sm ${
                msg.role === 'user' 
                ? 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-br-none border border-gray-200 dark:border-slate-700' 
                : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-bl-none border border-purple-100 dark:border-purple-500/20'
            }`}>
                <div className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">{msg.text}</div>
                <div className="text-[10px] opacity-50 mt-2 text-right dir-ltr">{msg.timestamp}</div>
            </div>
          </div>
        ))}

        {isLoading && (
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-purple-500 to-indigo-500 text-white flex items-center justify-center shrink-0">
                    <Sparkles size={16} className="animate-pulse" />
                </div>
                <div className="bg-white dark:bg-slate-800 px-4 py-3 rounded-2xl rounded-bl-none border border-purple-100 dark:border-purple-500/20">
                   <div className="flex gap-1">
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}}></div>
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}}></div>
                      <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}}></div>
                   </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-b-2xl p-4 border-x border-b border-gray-200 dark:border-slate-700/50">
        <div className="relative flex items-center gap-2">
            <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder={isOnline ? t('chat.placeholder') : t('chat.offlinePlaceholder')}
                disabled={!isOnline}
                rows={1}
                className="w-full bg-gray-100 dark:bg-slate-900/80 border border-gray-200 dark:border-slate-600 rounded-xl px-4 py-3 pr-12 text-slate-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all resize-none overflow-hidden max-h-32 disabled:opacity-50 disabled:cursor-not-allowed"
                style={{ minHeight: '50px' }}
            />
            <button
                onClick={handleSend}
                disabled={!input.trim() || isLoading || !isOnline}
                className="absolute left-2 p-2 bg-purple-600 hover:bg-purple-500 disabled:bg-gray-300 dark:disabled:bg-slate-700 text-white rounded-lg transition-all shadow-lg shadow-purple-500/20"
                style={dir === 'ltr' ? { right: '0.5rem', left: 'auto' } : {}}
            >
                {isLoading ? <RefreshCw size={20} className="animate-spin" /> : <Send size={20} className={dir === 'rtl' ? 'rotate-180' : ''} />}
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCcw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
}

export class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null,
    errorInfo: null
  };

  public static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
    this.setState({ errorInfo });
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-slate-900 text-white flex items-center justify-center p-4" dir="rtl">
          <div className="bg-slate-800 border border-red-500/50 rounded-2xl p-8 max-w-lg w-full shadow-2xl">
            <div className="flex items-center gap-4 text-red-500 mb-6">
              <AlertTriangle size={48} />
              <h1 className="text-2xl font-bold">متاسفانه خطایی رخ داده است</h1>
            </div>

            <p className="text-slate-300 mb-4">
              نرم‌افزار با یک خطای غیرمنتظره مواجه شد. لطفاً صفحه را بازنشانی کنید یا با پشتیبانی تماس بگیرید.
            </p>

            <div className="bg-slate-950 p-4 rounded-xl border border-slate-700 overflow-auto max-h-48 mb-6" dir="ltr">
              <code className="text-red-400 text-xs font-mono">
                {this.state.error && this.state.error.toString()}
              </code>
            </div>

            <button
              onClick={() => window.location.reload()}
              className="w-full bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all"
            >
              <RefreshCcw size={20} />
              بازنشانی نرم‌افزار
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Activity, FileText, TrendingUp, Menu, Zap, BarChart3, Info, Moon, Sun, Languages, Palette, MessageSquare, Wifi, WifiOff } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { DataEntry } from './components/DataEntry';
import { AnalysisResult } from './components/AnalysisResult';
import { MeasurementHistory } from './components/HistoryLog';
import { ExhaustDetails } from './components/ExhaustDetails';
import { ChatBot } from './components/ChatBot';
import { Exhaust, PollutantData, AIAnalysisResult, TabType } from './types';
import { INITIAL_EXHAUSTS } from './constants';
import { generateExhaustAnalysis } from './services/geminiService';
import { useSettings, AccentColor } from './contexts/SettingsContext';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType | 'chat'>('dashboard');

  // Initialize state from LocalStorage or fallback to constants
  const [exhausts, setExhausts] = useState<Exhaust[]>(() => {
    try {
      const saved = localStorage.getItem('ecomonitor_exhausts');
      return saved ? JSON.parse(saved) : INITIAL_EXHAUSTS;
    } catch (e) {
      console.error("Failed to load from local storage", e);
      return INITIAL_EXHAUSTS;
    }
  });

  const [aiAnalysis, setAiAnalysis] = useState<AIAnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // Navigation visual state
  const [isScrolled, setIsScrolled] = useState(false);

  const { theme, toggleTheme, language, toggleLanguage, t, dir, accentColor, setAccentColor, themeColors } = useSettings();

  // Persist data when changed
  useEffect(() => {
    localStorage.setItem('ecomonitor_exhausts', JSON.stringify(exhausts));
  }, [exhausts]);

  // Monitor Network Status
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Handle Scroll Effect
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleAddData = (exhaustId: string, newData: PollutantData, period: string) => {
    setExhausts(prev => prev.map(exhaust => {
      if (exhaust.id === parseInt(exhaustId)) {
        return {
          ...exhaust,
          data: newData,
          lastCheck: new Date().toLocaleDateString(language === 'fa' ? 'fa-IR' : 'en-US'),
          history: [
            ...exhaust.history, 
            {
                period: period,
                date: new Date().toLocaleDateString(language === 'fa' ? 'fa-IR' : 'en-US'),
                data: newData
            }
          ]
        };
      }
      return exhaust;
    }));
    setActiveTab('details');
  };

  const handleAddExhaust = (name: string, location: string) => {
    const newId = exhausts.length > 0 ? Math.max(...exhausts.map(e => e.id)) + 1 : 1;
    const newExhaust: Exhaust = {
      id: newId,
      name,
      location,
      data: { CO: 0, CO2: 0, SO2: 0, NOx: 0, PM: 0, O2: 0 },
      history: [],
      lastCheck: 'ثبت نشده'
    };
    setExhausts(prev => [...prev, newExhaust]);
  };

  const handleImportData = (data: Exhaust[]) => {
      setExhausts(data);
  };

  const handleAnalyze = async (exhaust: Exhaust, switchTab: boolean = true) => {
    if (!isOnline) {
      alert(t('error.offlineDesc'));
      return;
    }

    setIsAnalyzing(true);
    try {
      const resultText = await generateExhaustAnalysis(exhaust);
      setAiAnalysis({
        exhaustId: exhaust.id,
        analysis: resultText,
        timestamp: new Date().toLocaleString(language === 'fa' ? 'fa-IR' : 'en-US')
      });
      if (switchTab) setActiveTab('analysis');
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: t('nav.dashboard'), icon: Activity },
    { id: 'details', label: t('nav.details'), icon: Info },
    { id: 'data-entry', label: t('nav.dataEntry'), icon: FileText },
    { id: 'analysis', label: t('nav.analysis'), icon: TrendingUp },
    { id: 'chat', label: t('nav.chat'), icon: MessageSquare },
    { id: 'history', label: t('nav.history'), icon: BarChart3 }
  ];

  const colors: { id: AccentColor; bg: string }[] = [
    { id: 'blue', bg: 'bg-blue-600' },
    { id: 'emerald', bg: 'bg-emerald-600' },
    { id: 'violet', bg: 'bg-violet-600' },
    { id: 'amber', bg: 'bg-amber-600' },
    { id: 'rose', bg: 'bg-rose-600' },
  ];

  return (
    <div 
      className="min-h-screen bg-gray-50 dark:bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] dark:from-slate-900 dark:via-slate-900 dark:to-black text-slate-900 dark:text-white transition-colors duration-300" 
      dir={dir}
      style={{
        '--theme-primary': themeColors.primary,
        '--theme-hover': themeColors.hover,
        '--theme-light': themeColors.light,
        '--theme-text': themeColors.text,
      } as React.CSSProperties}
    >
      <div className="max-w-7xl mx-auto p-4 md:p-6 lg:p-8">

        {/* Header */}
        <header className="mb-10 animate-in slide-in-from-top-5 duration-700">
          <div className="bg-white dark:bg-slate-800 rounded-3xl p-8 shadow-xl dark:shadow-slate-900/20 border border-gray-200 dark:border-slate-700 relative overflow-hidden transition-all duration-300">
             {/* Gradient Background based on Theme */}
             <div 
               className="absolute top-0 right-0 w-full h-full opacity-0 dark:opacity-20 pointer-events-none transition-colors duration-500"
               style={{ background: `linear-gradient(to right, ${themeColors.primary}, transparent)` }}
             />

            <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl md:text-4xl font-black mb-2 tracking-tight">
                  {t('app.title')} <span className="text-transparent bg-clip-text" style={{ backgroundImage: `linear-gradient(to right, ${themeColors.primary}, ${themeColors.hover})` }}>EcoMonitor</span>
                </h1>
                <p className="text-slate-600 dark:text-slate-400 font-medium text-lg max-w-2xl">
                  {t('app.subtitle')}
                </p>
              </div>

              <div className="flex flex-col sm:flex-row items-center gap-4">

                {/* Online Status Indicator */}
                <div 
                  className={`flex items-center gap-2 px-3 py-2 rounded-xl border text-sm font-bold transition-all ${
                    isOnline 
                      ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800 text-emerald-600 dark:text-emerald-400' 
                      : 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-600 dark:text-red-400'
                  }`}
                  title={isOnline ? t('status.online') : t('status.offline')}
                >
                  {isOnline ? <Wifi size={18} /> : <WifiOff size={18} />}
                  <span className="hidden sm:inline">{isOnline ? t('status.online') : t('status.offline')}</span>
                </div>

                {/* Color Picker */}
                <div className="flex items-center gap-2 p-2 bg-gray-100 dark:bg-slate-900/50 rounded-xl border border-gray-200 dark:border-slate-700">
                    <Palette size={16} className="text-slate-500 ml-1" />
                    {colors.map(c => (
                        <button
                            key={c.id}
                            onClick={() => setAccentColor(c.id)}
                            className={`w-6 h-6 rounded-full transition-transform hover:scale-110 ${c.bg} ${accentColor === c.id ? 'ring-2 ring-offset-2 ring-slate-400 dark:ring-white scale-110' : 'opacity-70 hover:opacity-100'}`}
                        />
                    ))}
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={toggleTheme}
                        className="p-3 rounded-xl bg-gray-100 dark:bg-white/10 text-slate-700 dark:text-white border border-gray-200 dark:border-white/10 hover:bg-gray-200 dark:hover:bg-white/20 transition-all"
                    >
                        {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                    </button>
                    <button 
                        onClick={toggleLanguage}
                        className="p-3 rounded-xl bg-gray-100 dark:bg-white/10 text-slate-700 dark:text-white border border-gray-200 dark:border-white/10 hover:bg-gray-200 dark:hover:bg-white/20 transition-all font-bold w-12"
                    >
                        {language === 'fa' ? 'En' : 'فا'}
                    </button>
                </div>

                <div className="hidden md:flex items-center gap-3 bg-blue-50 dark:bg-white/10 backdrop-blur-md px-4 py-2.5 rounded-xl border border-blue-100 dark:border-white/10">
                    <Zap className="text-amber-500 dark:text-yellow-400 fill-amber-500 dark:fill-yellow-400" />
                    <span className="font-bold text-slate-800 dark:text-white">{t('gemini.powered')}</span>
                </div>
              </div>
            </div>
          </div>
        </header>

        {/* Navigation - Always visible sticky dock with compact effect on scroll */}
        <nav 
          className={`
            flex flex-row items-center gap-2 mb-8 
            backdrop-blur-xl sticky top-4 z-50 
            overflow-x-auto custom-scrollbar
            transition-all duration-500 cubic-bezier(0.4, 0, 0.2, 1)
            border
            ${isScrolled 
              ? 'bg-white/95 dark:bg-slate-800/95 shadow-2xl border-gray-300 dark:border-slate-600 p-2 rounded-[2rem] mx-0 md:mx-auto md:max-w-4xl' 
              : 'bg-white/60 dark:bg-slate-900/50 shadow-lg border-gray-200 dark:border-slate-800 p-3 rounded-2xl w-full'}
          `}
        >
          {navItems.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`
                flex-1 min-w-[120px] rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 whitespace-nowrap
                ${isScrolled ? 'py-3 px-4 text-sm' : 'py-4 px-6 text-sm md:text-base'}
                ${activeTab === tab.id 
                  ? 'text-white shadow-md scale-[1.02]' 
                  : 'bg-transparent text-slate-500 dark:text-slate-400 hover:bg-gray-100/50 dark:hover:bg-slate-700/50 hover:text-slate-900 dark:hover:text-slate-200'}
              `}
              style={activeTab === tab.id ? { backgroundColor: themeColors.primary, boxShadow: `0 4px 12px ${themeColors.primary}40` } : {}}
            >
              <tab.icon size={isScrolled ? 18 : 22} strokeWidth={2.5} className="transition-all duration-300" />
              {tab.label}
            </button>
          ))}
        </nav>

        {/* Main Content Area */}
        <main className="min-h-[500px]">
          {activeTab === 'dashboard' && (
            <Dashboard 
              exhausts={exhausts} 
              onAnalyze={(e) => handleAnalyze(e, true)} 
              isAnalyzing={isAnalyzing} 
              isOnline={isOnline}
            />
          )}

          {activeTab === 'details' && (
            <ExhaustDetails 
              exhausts={exhausts}
              aiAnalysis={aiAnalysis}
              isAnalyzing={isAnalyzing}
              onAnalyze={handleAnalyze}
              isOnline={isOnline}
            />
          )}

          {activeTab === 'data-entry' && (
            <DataEntry 
              exhausts={exhausts} 
              onAddData={handleAddData} 
              onAddExhaust={handleAddExhaust}
              onImportData={handleImportData}
            />
          )}

          {activeTab === 'analysis' && (
            <AnalysisResult 
              analysis={aiAnalysis}
              exhausts={exhausts} 
              onBack={() => setActiveTab('dashboard')}
            />
          )}

          {activeTab === 'chat' && (
             <ChatBot isOnline={isOnline} />
          )}

          {activeTab === 'history' && (
            <MeasurementHistory exhausts={exhausts} />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCcw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
}

export class ErrorBoundary extends React.Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null,
    errorInfo: null
  };

  public static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
    this.setState({ errorInfo });
  }

  public render() {
    if (this.state.hasError) {
