          {activeTab === 'analysis' && (
            <AnalysisResult 
              analysis={aiAnalysis}
              exhausts={exhausts} 
              onBack={() => setActiveTab('dashboard')}
            />
          )}

          {activeTab === 'chat' && (
             <ChatBot isOnline={isOnline} />
          )}

          {activeTab === 'history' && (
            <MeasurementHistory exhausts={exhausts} />
          )}
        </main>
      </div>
    </div>
  );
};

